BEGIN; CREATE OR REPLACE FUNCTION public.undo_shipments_v1(p_shipment_ids uuid[]) RETURNS jsonb LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$ DECLARE v_user_id uuid := auth.uid(); v_ids uuid[]; v_requested_count integer; v_locked_count integer; v_shipment_id uuid; v_result jsonb; v_total_transactions integer := 0; BEGIN IF v_user_id IS NULL OR NOT public.is_admin() THEN RAISE EXCEPTION 'Chi Admin moi duoc huy nhieu chuyen hang.'; END IF; IF p_shipment_ids IS NULL OR cardinality(p_shipment_ids) = 0 THEN RAISE EXCEPTION 'Vui long chon it nhat mot chuyen hang.'; END IF; IF array_position(p_shipment_ids, NULL) IS NOT NULL THEN RAISE EXCEPTION 'Danh sach chuyen hang khong hop le.'; END IF; SELECT array_agg(x.id ORDER BY x.id), count(*) INTO v_ids, v_requested_count FROM (SELECT DISTINCT unnest(p_shipment_ids) AS id) x; IF v_requested_count <> cardinality(p_shipment_ids) THEN RAISE EXCEPTION 'Danh sach chuyen hang bi trung lap.'; END IF; IF v_requested_count > 100 THEN RAISE EXCEPTION 'Moi lan chi duoc huy toi da 100 chuyen hang.'; END IF; PERFORM 1 FROM public.inventory_transactions t WHERE t.shipment_id = ANY(v_ids) AND t.deleted_at IS NULL ORDER BY t.shipment_id, t.id FOR UPDATE; PERFORM 1 FROM public.delivery_plans p WHERE p.id IN (SELECT DISTINCT t.delivery_plan_id FROM public.inventory_transactions t WHERE t.shipment_id = ANY(v_ids) AND t.deleted_at IS NULL AND t.delivery_plan_id IS NOT NULL) ORDER BY p.id FOR UPDATE; PERFORM 1 FROM public.shipment_logs s WHERE s.id = ANY(v_ids) AND s.deleted_at IS NULL ORDER BY s.id FOR UPDATE; GET DIAGNOSTICS v_locked_count = ROW_COUNT; IF v_locked_count <> v_requested_count THEN RAISE EXCEPTION 'Co chuyen hang khong ton tai hoac da bi huy. Khong co chuyen nao duoc thay doi.'; END IF; FOREACH v_shipment_id IN ARRAY v_ids LOOP v_result := public.undo_shipment(v_shipment_id); v_total_transactions := v_total_transactions + COALESCE((v_result->>'soft_deleted_tx_count')::integer, 0); END LOOP; RETURN jsonb_build_object('success', true, 'shipment_count', v_requested_count, 'soft_deleted_tx_count', v_total_transactions, 'message', 'Da huy toan bo chuyen hang da chon trong mot lan xu ly. Lich su van duoc giu lai.'); END; $$; REVOKE ALL ON FUNCTION public.undo_shipments_v1(uuid[]) FROM PUBLIC, anon; GRANT EXECUTE ON FUNCTION public.undo_shipments_v1(uuid[]) TO authenticated; NOTIFY pgrst, 'reload schema'; COMMIT;
